import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import API from '../services/api';
import './AdminAnalytics.css';

function AdminAnalytics() {
  const { user } = useAuth();
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [period, setPeriod] = useState('week');

  // Данные с бэкенда
  const [dashboard, setDashboard] = useState(null);
  const [popularListings, setPopularListings] = useState([]);
  const [priceStats, setPriceStats] = useState(null);

  useEffect(() => {
    loadAnalytics();
  }, [period]);

  const loadAnalytics = async () => {
    setLoading(true);
    setError(null);

    try {
      // Загружаем по отдельности чтобы видеть где ошибка
      console.log('Загружаем dashboard...');
      const dashboardRes = await API.get('/analytics/dashboard?days=30');
      setDashboard(dashboardRes.data);

      console.log('Загружаем популярные...');
      const popularRes = await API.get(`/analytics/listings/popular?period=${period}&limit=10`);
      setPopularListings(popularRes.data);

      console.log('Загружаем цены...');
      const pricesRes = await API.get('/analytics/prices');
      setPriceStats(pricesRes.data);

    } catch (err) {
      console.error('❌ Ошибка загрузки:', err);
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  // Проверка прав доступа
  if (!user) {
    return (
      <div className="analytics-error">
        <h2>🚫 Требуется авторизация</h2>
        <p>Войдите в систему</p>
      </div>
    );
  }

  if (user.role_id !== 1) {
    return (
      <div className="analytics-error">
        <h2>🚫 Доступ запрещен</h2>
        <p>Эта страница доступна только администраторам</p>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="loader">
        <div className="spinner"></div>
        <p>Загрузка аналитики...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="error-container">
        <h2>❌ Ошибка</h2>
        <p>{error}</p>
        <button onClick={loadAnalytics} className="retry-btn">
          Повторить попытку
        </button>
      </div>
    );
  }

  return (
    <div className="analytics-page">
      <h1>📊 Аналитика</h1>

      {/* Кнопки периода */}
      <div className="period-selector">
        <button
          className={period === 'day' ? 'active' : ''}
          onClick={() => setPeriod('day')}
        >
          День
        </button>
        <button
          className={period === 'week' ? 'active' : ''}
          onClick={() => setPeriod('week')}
        >
          Неделя
        </button>
        <button
          className={period === 'month' ? 'active' : ''}
          onClick={() => setPeriod('month')}
        >
          Месяц
        </button>
      </div>

      {/* Карточки с метриками */}
      {dashboard && (
        <div className="metrics-grid">
          <div className="metric-card">
            <h3>Всего объявлений</h3>
            <p className="metric-value">{dashboard.total_listings || 0}</p>
          </div>
          <div className="metric-card">
            <h3>Активных сегодня</h3>
            <p className="metric-value">{dashboard.active_today || 0}</p>
          </div>
          <div className="metric-card">
            <h3>Просмотров сегодня</h3>
            <p className="metric-value">{dashboard.views_today || 0}</p>
          </div>
          <div className="metric-card">
            <h3>Новых сегодня</h3>
            <p className="metric-value">{dashboard.new_listings_today || 0}</p>
          </div>
        </div>
      )}

      {/* Популярные объявления */}
      <div className="analytics-card">
        <h2>🔥 Популярные за {period}</h2>
        <div className="listings-list">
          {popularListings.length > 0 ? (
            popularListings.map((item, index) => (
              <div key={item.listing_id || index} className="listing-item">
                <span className="rank">{index + 1}</span>
                <div className="listing-info">
                  <h4>{item.title || 'Без названия'}</h4>
                  <p>{item.address || 'Адрес не указан'}</p>
                </div>
                <div className="listing-stats">
                  <span className="views">👁 {item.views || 0}</span>
                  <span className="price">
                    {item.price ? item.price.toLocaleString() : 0} ₽
                  </span>
                </div>
              </div>
            ))
          ) : (
            <p className="no-data">Нет данных за период</p>
          )}
        </div>
      </div>

      {/* Статистика цен */}
      {priceStats && (
        <div className="analytics-card">
          <h2>💰 Статистика цен</h2>
          <div className="price-stats">
            <div className="stats-grid">
              <div className="stat-item">
                <span className="stat-label">Всего активных:</span>
                <span className="stat-value">{priceStats.summary?.total_listings || 0}</span>
              </div>
              <div className="stat-item">
                <span className="stat-label">Средняя цена:</span>
                <span className="stat-value">
                  {priceStats.summary?.avg_price?.toLocaleString() || 0} ₽
                </span>
              </div>
              <div className="stat-item">
                <span className="stat-label">Цена за м²:</span>
                <span className="stat-value">
                  {priceStats.summary?.avg_price_per_m2?.toLocaleString() || 0} ₽
                </span>
              </div>
            </div>

            {priceStats.by_property_type?.length > 0 && (
              <>
                <h3>По типам</h3>
                <table className="stats-table">
                  <thead>
                    <tr>
                      <th>Тип</th>
                      <th>Кол-во</th>
                      <th>Ср. цена</th>
                      <th>₽/м²</th>
                    </tr>
                  </thead>
                  <tbody>
                    {priceStats.by_property_type.map((item, idx) => (
                      <tr key={idx}>
                        <td>{item.type || 'Другое'}</td>
                        <td>{item.listings_count || 0}</td>
                        <td>{item.avg_price?.toLocaleString() || 0} ₽</td>
                        <td>{item.avg_price_per_m2?.toLocaleString() || 0} ₽</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

export default AdminAnalytics;
